function switchUnit(t){var e=t.closest("[itemscope]");if(e){var r=e.querySelector(".price-display");e.querySelectorAll("[data-unit]").forEach(function(t){t.classList.remove("bg-red-100","text-red-800"),t.classList.add("bg-gray-100","text-gray-500")}),t.classList.remove("bg-gray-100","text-gray-500"),t.classList.add("bg-red-100","text-red-800"),r&&(r.textContent=t.getAttribute("data-price")+" ₽")}}